import{_ as e,o as t,c as r,af as a}from"./chunks/framework.5D6DWnkB.js";const h=JSON.parse('{"title":"实战：如何优雅地更换博客域名（附 301 权重转移指南）","description":"","frontmatter":{"title":"实战：如何优雅地更换博客域名（附 301 权重转移指南）","date":"2026-04-02T00:00:00.000Z"},"headers":[],"relativePath":"tools/domain-migration.md","filePath":"tools/domain-migration.md"}'),l={name:"tools/domain-migration.md"};function n(s,o,i,d,c,g){return t(),r("div",null,[...o[0]||(o[0]=[a('<h1 id="实战-如何优雅地更换博客域名-附-301-权重转移指南" tabindex="-1">实战：如何优雅地更换博客域名（附 301 权重转移指南） <a class="header-anchor" href="#实战-如何优雅地更换博客域名-附-301-权重转移指南" aria-label="Permalink to &quot;实战：如何优雅地更换博客域名（附 301 权重转移指南）&quot;">​</a></h1><p>搭建完独立博客后，很多朋友一开始可能只是随便买了个便宜的“练手域名”（比如纯数字的 <code>.xyz</code>），等网站慢慢有了起色，就想换一个更正规、更好记的长线域名。</p><p>但这带来了一个棘手的问题：<strong>换了新域名，老域名的流量和搜索引擎（SEO）收录的权重不就白白流失了吗？</strong></p><p>今天这篇教程，就带你实战演示如何通过 Cloudflare 完美实现<strong>新旧域名无缝交接，并利用 301 永久重定向把老域名的权重全部转移到新家。</strong></p><h2 id="第一步-选购心仪的长线域名" tabindex="-1">第一步：选购心仪的长线域名 <a class="header-anchor" href="#第一步-选购心仪的长线域名" aria-label="Permalink to &quot;第一步：选购心仪的长线域名&quot;">​</a></h2><p>挑域名是个技术活，核心原则就三个：</p><ol><li><strong>辨识度高</strong>：首选 <code>.com</code> / <code>.net</code>，或者代表极客属性的 <code>.dev</code> / <code>.me</code>。如果预算有限，选一个不带“溢价词”的普通双拼字母 <code>.xyz</code> 也是不错的选择（比如我的 <code>leechbox.xyz</code>）。</li><li><strong>避开天价续费坑</strong>：购买时千万不要只看“首年 1 刀”的噱头，付款前必须确认第二年的 <strong>Renewal Price (续费价格)</strong>。通常几十块钱以内属于正常，上百甚至几千的直接 pass。</li><li><strong>海外注册商优先</strong>：如果是用来做 IT 实验和挂载节点，推荐使用 Spaceship、Namecheap 或直接在 Cloudflare 购买，免除繁琐的备案环节。</li></ol><h2 id="第二步-cloudflare-接管与绑定新域名" tabindex="-1">第二步：Cloudflare 接管与绑定新域名 <a class="header-anchor" href="#第二步-cloudflare-接管与绑定新域名" aria-label="Permalink to &quot;第二步：Cloudflare 接管与绑定新域名&quot;">​</a></h2><p>在注册商买下域名后，我们需要把它接入 Cloudflare 的强大网络中。</p><ol><li><strong>修改 Nameservers</strong>：在 Cloudflare 添加你的新域名，获取它分配给你的两条 NS 记录。回到域名购买平台（如 Spaceship），将默认 DNS 改为 Custom DNS，填入这两条记录并保存。</li><li><strong>绑定至博客</strong>：进入 Cloudflare 的 <strong>Workers &amp; Pages</strong>，找到你的博客项目。点击 <strong>自定义域 (Custom Domains)</strong>，将新域名添加进去。等待几分钟变成绿色的“Active”，你的新域名就能打开网站了！</li></ol><h2 id="第三步-老域名-301-重定向-最核心一步" tabindex="-1">第三步：老域名 301 重定向（最核心一步！） <a class="header-anchor" href="#第三步-老域名-301-重定向-最核心一步" aria-label="Permalink to &quot;第三步：老域名 301 重定向（最核心一步！）&quot;">​</a></h2><p><strong>绝对不要</strong>把新旧两个域名同时绑在博客上不管，这会导致搜索引擎判定你恶意制造“重复内容 (Duplicate Content)”，双双降权！</p><p>正确的做法是：设定新域名为唯一主域名，把老域名的流量瞬间“弹射”到新域名上。</p><p><strong>具体操作如下：</strong></p><ol><li><p>进入老域名的 Cloudflare 控制面板。</p></li><li><p>点击左侧菜单的 <strong>规则 (Rules)</strong> -&gt; <strong>页面规则 (Page Rules)</strong>。</p></li><li><p>点击“创建页面规则”，按以下格式填写：</p><ul><li><strong>URL 匹配</strong>：<code>*老域名.xyz/*</code> （比如：<code>*912480160.xyz/*</code>，注意前后的星号不能漏）</li><li><strong>选取设置</strong>：选择 <strong>转发 URL (Forwarding URL)</strong></li><li><strong>状态代码</strong>：选择 <strong>301 - 永久重定向</strong></li><li><strong>目标 URL</strong>：<code>https://你的新域名.xyz/$1</code> （比如：<code>https://leechbox.xyz/$1</code>，末尾的 <code>$1</code> 是为了确保文章路径精确对应跳回）。</li></ul></li><li><p>忽略可能弹出的 DNS 警告提示，直接点击保存并部署。</p></li></ol><h2 id="最终效果" tabindex="-1">最终效果 <a class="header-anchor" href="#最终效果" aria-label="Permalink to &quot;最终效果&quot;">​</a></h2><p>现在，任何试图访问你老域名文章的人（或者爬虫），都会被 HTTP 301 状态码瞬间传送到你的新域名对应文章下。老链接依然存活，SEO 权重完美继承，你的网站也终于换上了高大上的新招牌！</p>',17)])])}const u=e(l,[["render",n]]);export{h as __pageData,u as default};
